        Reader reader = null;
        String base = "";
        // WHEN/THEN: parsing null Reader must throw IllegalArgumentException by contract → exercises B0→B3→B4 path
        assertThrows(IllegalArgumentException.class, () -> parser.parseInput(reader, base),
